def validate_xml_file(file_path: str, max_size_bytes: int = 10 * 1024 * 1024,
                      max_depth: int = 100, allowed_root_tags: Optional[list] = None,
                      required_elements: Optional[list] = None) -> XMLValidationResult:
    """
    Reads and validates an XML document from a file path.

    Args:
        file_path: Path to the XML file.
        max_size_bytes: Maximum allowed file size in bytes (default 10MB).
        max_depth: Maximum allowed nesting depth.
        allowed_root_tags: Optional list of allowed root element tag names.
        required_elements: Optional list of element tag names that must be present.

    Returns:
        XMLValidationResult with validation details.
    """
    # Validate file path - prevent path traversal
    file_path = os.path.realpath(file_path)

    if not os.path.isfile(file_path):
        raise XMLValidationError("The specified file does not exist or is not a regular file.")

    # Check file extension
    _, ext = os.path.splitext(file_path)
    if ext.lower() not in ('.xml', '.xhtml', '.svg', '.xsd', '.xsl'):
        raise XMLValidationError(
            f"File extension '{_sanitize_string(ext)}' is not a recognized XML extension."
        )

    # Check file size before reading
    file_size = os.path.getsize(file_path)
    if file_size > max_size_bytes:
        raise XMLValidationError(
            f"File size ({file_size} bytes) exceeds maximum allowed size "
            f"of {max_size_bytes} bytes."
        )

    try:
        with open(file_path, 'rb') as f:
            xml_content = f.read(max_size_bytes + 1)
    except (IOError, OSError) as e:
        raise XMLValidationError(f"Unable to read file: {_sanitize_error_message(str(e))}")

    return validate_xml_content(
        xml_content,
        max_size_bytes=max_size_bytes,
        max_depth=max_depth,
        allowed_root_tags=allowed_root_tags,
        required_elements=required_elements
    )


